import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(n, edges) {
    // Build the adjacency list
    const adj = Array.from({ length: n }, () => []);
    const reverseAdj = Array.from({ length: n }, () => []);
    for (const [u, v, w] of edges) {
        adj[u].push([v, w]);
        reverseAdj[v].push([u, w]);
    }

    // dist[u][0] = cost to reach u without using any switch
    // dist[u][1] = cost to reach u with using a switch at u
    const dist = Array.from({ length: n }, () => [Infinity, Infinity]);
    dist[0][0] =  0;

    const heap = new MinPriorityQueue({
        priority: (item) => item.cost
    });
    heap.enqueue({ node: 0, usedSwitch: 0, cost: 0 });

    while (!heap.isEmpty()) {
        const { node: u, usedSwitch: hasUsed, cost: currentCost } = heap.dequeue().element;
        if (u === n - 1) {
            return currentCost;
        }
        if (currentCost > dist[u][hasUsed]) {
            continue;
        }

        // Option 1: Do not use the switch at u (if not used yet)
        if (hasUsed === 0) {
            for (const [v, w] of adj[u]) {
                const newCost = currentCost + w;
                if (newCost < dist[v][0]) {
                    dist[v][0] = newCost;
                    heap.enqueue({ node: v, usedSwitch: 0, cost: newCost });
                }
            }
        }

        // Option 2: Use the switch at u (if not used yet)
        if (hasUsed === 0) {
            for (const [v, w] of reverseAdj[u]) {
                const newCost = currentCost + 2 * w;
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost;
                    heap.enqueue({ node: v, usedSwitch: 1, cost: newCost });
                }
            }
        }

        // Option 3: Already used the switch, can only proceed normally
        if (hasUsed === 1) {
            for (const [v, w] of adj[u]) {
                const newCost = currentCost + w;
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost;
                    heap.enqueue({ node: v, usedSwitch: 1, cost: newCost });
                }
            }
        }
    }

    const result = Math.min(dist[n - 1][0], dist[n - 1][1]);
    return result === Infinity ? -1 : result;
}

