import java.util.PriorityQueue

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val adj = Array(n.toInt()) { mutableListOf<Pair<Int, Long>>() }
    val reverseAdj = Array(n.toInt()) { mutableListOf<Pair<Int, Long>>() }
    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val w = edge[2]
        adj[u].add(v to w)
        reverseAdj[v].add(u to w)
    }

    val dist = Array(n.toInt()) { LongArray(2) { Long.MAX_VALUE } }
    dist[0][0] = 0

    val heap = PriorityQueue<Pair<Long, Pair<Int, Int>>>(compareBy { it.first })
    heap.add(0L to (0 to 0))

    while (heap.isNotEmpty()) {
        val (currentCost, state) = heap.poll()
        val (u, hasUsed) = state
        if (u == n.toInt() - 1) {
            return currentCost
        }
        if (currentCost > dist[u][hasUsed]) {
            continue
        }

        if (hasUsed == 0) {
            for ((v, w) in adj[u]) {
                val newCost = currentCost + w
                if (newCost < dist[v][0]) {
                    dist[v][0] = newCost
                    heap.add(newCost to (v to 0))
                }
            }
        }

        if (hasUsed == 0) {
            for ((v, w) in reverseAdj[u]) {
                val newCost = currentCost + 2 * w
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost
                    heap.add(newCost to (v to 1))
                }
            }
        }

        if (hasUsed == 1) {
            for ((v, w) in adj[u]) {
                val newCost = currentCost + w
                if (newCost < dist[v][1]) {
                    dist[v][1] = newCost
                    heap.add(newCost to (v to 1))
                }
            }
        }
    }

    val result = minOf(dist[n.toInt() - 1][0], dist[n.toInt() - 1][1])
    return if (result == Long.MAX_VALUE) -1 else result
}
